package com.multilanglearner.ui.regulation

import androidx.lifecycle.ViewModel
import androidx.lifecycle.viewModelScope
import com.multilanglearner.data.repository.RegulationRepository
import com.multilanglearner.domain.model.RegulationCountry
import dagger.hilt.android.lifecycle.HiltViewModel
import kotlinx.coroutines.flow.*
import kotlinx.coroutines.launch
import javax.inject.Inject

data class RegulationUiState(
    val countries: List<RegulationCountry> = emptyList(),
    val selectedCountry: String = ""
)

@HiltViewModel
class RegulationViewModel @Inject constructor(
    private val repository: RegulationRepository
) : ViewModel() {
    private val _uiState = MutableStateFlow(RegulationUiState())
    val uiState: StateFlow<RegulationUiState> = _uiState.asStateFlow()

    fun loadRegulations() {
        viewModelScope.launch {
            val countries = repository.getAll()
            _uiState.update { it.copy(
                countries = countries,
                selectedCountry = countries.firstOrNull()?.code ?: ""
            )}
        }
    }

    fun selectCountry(code: String) { _uiState.update { it.copy(selectedCountry = code) } }

    fun addCountry(code: String, name: String) {
        viewModelScope.launch {
            repository.addItem(code, name, "en-US", "$name - 示例条目", "请编辑此条目或添加新法规。")
            loadRegulations()
            _uiState.update { it.copy(selectedCountry = code) }
        }
    }

    fun addItem(title: String, content: String) {
        val code = _uiState.value.selectedCountry
        val country = _uiState.value.countries.find { it.code == code } ?: return
        viewModelScope.launch {
            repository.addItem(code, country.name, country.lang, title, content)
            loadRegulations()
        }
    }

    fun deleteItem(id: Long) {
        viewModelScope.launch { repository.deleteItem(id); loadRegulations() }
    }
}
